using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;
using System.Security.Claims;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers only)
        group.MapGet("/", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            if (!user.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipments = await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => s.ToDto())
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Get shipments for the current customer
        group.MapGet("/my", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            var email = user.FindFirstValue(ClaimTypes.Email) ?? "";
            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => s.ToDto())
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Track by tracking number (any authenticated user)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            return shipment is null ? Results.NotFound() : Results.Ok(shipment.ToDto());
        });

        // Update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", async (int id, UpdateStatusRequest request, ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            if (!user.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = request.Status;
            if (request.EstimatedDelivery.HasValue)
                shipment.EstimatedDelivery = request.EstimatedDelivery.Value;

            await db.SaveChangesAsync();
            return Results.Ok(shipment.ToDto());
        });

        // Create shipment (dispatchers only)
        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            if (!user.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = dto.Status,
                ShippedDate = dto.ShippedDate,
                EstimatedDelivery = dto.EstimatedDelivery,
                CustomerEmail = dto.CustomerEmail,
                Description = dto.Description
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", shipment.ToDto());
        });
    }
}

public record UpdateStatusRequest(ShipmentStatus Status, DateTime? EstimatedDelivery);

using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
