                        <label class="form-label">Origin</label>
                        <input type="text" class="form-control" @bind="newShipment.Origin" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Destination</label>
                        <input type="text" class="form-control" @bind="newShipment.Destination" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Customer Email</label>
                        <input type="email" class="form-control" @bind="newShipment.CustomerEmail" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Description</label>
                        <input type="text" class="form-control" @bind="newShipment.Description" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Estimated Delivery</label>
                        <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CloseModal">Cancel</button>
                    <button class="btn btn-success" @onclick="CreateShipment">Create</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private bool showStatusEditor;
    private bool showCreateForm;
    private ShipmentDto? editingShipment;
    private ShipmentStatus newStatus;
    private DateTime newEstimatedDelivery = DateTime.Today.AddDays(7);
    private ShipmentDto newShipment = new() { ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.Today.AddDays(7) };

    private IEnumerable<ShipmentDto> FilteredShipments => shipments!
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private void EditStatus(ShipmentDto shipment)
    {
        editingShipment = shipment;
        newStatus = shipment.Status;
        newEstimatedDelivery = shipment.EstimatedDelivery;
        showStatusEditor = true;
        showCreateForm = false;
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        showStatusEditor = false;
    }

    private void CloseModal()
    {
        showStatusEditor = false;
        showCreateForm = false;
    }

    private async Task SaveStatus()
    {
        var response = await Http.PutAsJsonAsync($"/api/shipments/{editingShipment!.Id}/status",
            new { Status = newStatus, EstimatedDelivery = newEstimatedDelivery });

        if (response.IsSuccessStatusCode)
        {
            editingShipment.Status = newStatus;
            editingShipment.EstimatedDelivery = newEstimatedDelivery;
        }
        CloseModal();
    }

    private async Task CreateShipment()
    {
        newShipment.Status = ShipmentStatus.Pending;
        newShipment.ShippedDate = DateTime.UtcNow;
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            var created = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            shipments!.Insert(0, created!);
            newShipment = new() { ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.Today.AddDays(7) };
        }
        CloseModal();
    }

    private string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/my-shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>My Shipments</PageTitle>

<h2>🚚 My Shipments</h2>

@if (shipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!shipments.Any())
{
    <div class="alert alert-info">
        <p>No shipments found for your account. Use the tracking form below to look up a shipment.</p>
    </div>
}
else
{
    <div class="row">
        @foreach (var s in shipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100 @GetCardBorder(s.Status)">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@s.TrackingNumber</strong>
                        <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                    </div>
                    <div class="card-body">
                        <p class="mb-1"><strong>From:</strong> @s.Origin</p>
                        <p class="mb-1"><strong>To:</strong> @s.Destination</p>
                        <p class="mb-1"><strong>Description:</strong> @s.Description</p>
                        <hr />
                        <p class="mb-1"><strong>Shipped:</strong> @s.ShippedDate.ToString("MMM dd, yyyy")</p>
                        <p class="mb-0">
                            <strong>Estimated Delivery:</strong>
                            <span class="@(s.EstimatedDelivery < DateTime.UtcNow && s.Status != ShipmentStatus.Delivered ? "text-danger fw-bold" : "")">
                                @s.EstimatedDelivery.ToString("MMM dd, yyyy")
                            </span>
                        </p>
                        @if (s.Status != ShipmentStatus.Delivered)
                        {
                            var daysLeft = (s.EstimatedDelivery - DateTime.UtcNow).Days;
                            <p class="mt-2 mb-0 text-muted">
                                @if (daysLeft > 0)
                                {
                                    <span>📅 @daysLeft day(s) until delivery</span>
                                }
                                else
                                {
                                    <span class="text-danger">⚠️ Delivery overdue</span>
                                }
                            </p>
                        }
                        else
                        {
                            <p class="mt-2 mb-0 text-success">✅ Delivered</p>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

<hr />
<h4>🔍 Track a Shipment</h4>
<div class="input-group mb-3" style="max-width: 500px;">
    <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-2026-001)"
           @bind="trackingInput" @onkeydown="HandleTrackKeyDown" />
    <button class="btn btn-outline-primary" @onclick="TrackShipment">Track</button>
</div>

@if (trackingError is not null)
{
    <div class="alert alert-warning">@trackingError</div>
}

@if (trackedShipment is not null)
{
    <div class="card border-primary" style="max-width: 500px;">
        <div class="card-header bg-primary text-white">
            Tracking Result: @trackedShipment.TrackingNumber
        </div>
        <div class="card-body">
            <p><strong>Status:</strong> <span class="badge @GetStatusBadge(trackedShipment.Status)">@trackedShipment.Status</span></p>
            <p><strong>From:</strong> @trackedShipment.Origin</p>
            <p><strong>To:</strong> @trackedShipment.Destination</p>
            <p><strong>Estimated Delivery:</strong> @trackedShipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
        </div>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string trackingInput = "";
    private string? trackingError;
    private ShipmentDto? trackedShipment;

    protected override async Task OnInitializedAsync()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments/my");
    }

    private async Task HandleTrackKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        trackingError = null;
        trackedShipment = null;

        if (string.IsNullOrWhiteSpace(trackingInput))
        {
            trackingError = "Please enter a tracking number.";
            return;
        }

        var response = await Http.GetAsync($"/api/shipments/track/{trackingInput.Trim()}");
        if (response.IsSuccessStatusCode)
        {
            trackedShipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
        }
        else
        {
            trackingError = $"Shipment '{trackingInput.Trim()}' not found.";
        }
    }

    private string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private string GetCardBorder(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "border-danger",
        ShipmentStatus.Delivered => "border-success",
        ShipmentStatus.OutForDelivery => "border-warning",
        _ => ""
    };
}

