+    private string GetCardBorder(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Delayed => "border-danger",
+        ShipmentStatus.Delivered => "border-success",
+        ShipmentStatus.OutForDelivery => "border-warning",
+        _ => ""
+    };
+}
